// ── Theme toggle ──────────────────────────────────────────────────────────
(function () {
  const html = document.documentElement;
  const stored = localStorage.getItem("nw-theme");
  const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  const theme = stored || (prefersDark ? "dark" : "light");
  html.setAttribute("data-bs-theme", theme);

  document.addEventListener("DOMContentLoaded", function () {
    const btn = document.getElementById("themeToggle");
    const icon = document.getElementById("themeIcon");
    if (!btn) return;

    function updateIcon() {
      const current = html.getAttribute("data-bs-theme");
      icon.className =
        current === "dark" ? "bi bi-sun-fill" : "bi bi-moon-fill";
    }
    updateIcon();

    btn.addEventListener("click", function () {
      const current = html.getAttribute("data-bs-theme");
      const next = current === "dark" ? "light" : "dark";
      html.setAttribute("data-bs-theme", next);
      localStorage.setItem("nw-theme", next);
      updateIcon();
    });
  });
})();

// ── Clickable table rows ──────────────────────────────────────────────────
document.addEventListener("DOMContentLoaded", function () {
  document.querySelectorAll("[data-href]").forEach(function (el) {
    el.addEventListener("click", function (e) {
      if (
        e.target.tagName === "A" ||
        e.target.tagName === "BUTTON" ||
        e.target.tagName === "INPUT"
      )
        return;
      window.location.href = el.getAttribute("data-href");
    });
  });
});

// ── Order line item: auto-fill unit price from product dropdown ───────────
document.addEventListener("DOMContentLoaded", function () {
  const productSel = document.getElementById("lineProductId");
  const priceInput = document.getElementById("lineUnitPrice");
  if (productSel && priceInput) {
    productSel.addEventListener("change", function () {
      const opt = productSel.options[productSel.selectedIndex];
      const price = opt.getAttribute("data-price");
      if (price) priceInput.value = price;
      updateLineTotal();
    });
    const qtyInput = document.getElementById("lineQty");
    const totalSpan = document.getElementById("lineTotal");
    function updateLineTotal() {
      if (!qtyInput || !totalSpan) return;
      const qty = parseFloat(qtyInput.value) || 0;
      const price = parseFloat(priceInput.value) || 0;
      totalSpan.textContent = (qty * price).toFixed(2);
    }
    if (qtyInput) qtyInput.addEventListener("input", updateLineTotal);
    if (priceInput) priceInput.addEventListener("input", updateLineTotal);
  }
});
